[20154]={"Seal of Righteousness","20 Mana\nInstant\n[q]Fills the Paladin with holy spirit for 30 sec, granting each melee attack an additional [1.2 * ( 216 * 1.2 * 1.03 * Mainhand weapon max base speed / 100) + 0.03 * (Mainhand weapon max damage + Mainhand weapon min damage) / 2 + 1] Holy damage. Only one Seal can be active on the Paladin at any one time."},
[20162]={"Seal of the Crusader","40 Mana\nInstant\n[q]Fills the Paladin with the spirit of a crusader for 30 sec, granting 68 melee attack power. The Paladin also attacks 40% faster, but deals less damage with each attack. Only one Seal can be active on the Paladin at any one time.\n\n Unleashing this Seal's energy will judge an enemy for 20 sec, increasing Holy damage taken by up to 35. Your melee strikes will refresh the spell's duration. Only one Judgement per Paladin can be active at any one time."},
[20164]={"Seal of Justice","10% of base mana\nInstant\n[q]Fills the Paladin with the spirit of justice for 30 sec, giving each melee attack a chance to stun for 2 sec. Only one Seal can be active on the Paladin at any one time.\n\n Unleashing this Seal's energy will judge an enemy for 20 sec, preventing them from fleeing. Your melee strikes will refresh the spell's duration. Only one Judgement per Paladin can be active at any one time."},
[20165]={"Seal of Light","110 Mana\nInstant\n[q]Fills the Paladin with divine light for 30 sec, giving each melee attack a chance to heal the Paladin for 39. Only one Seal can be active on the Paladin at any one time.\n\n Unleashing this Seal's energy will judge an enemy for 20 sec, granting melee attacks made against the judged enemy a chance of healing the attacker for 25. Your melee strikes will refresh the spell's duration. Only one Judgement per Paladin can be active at any one time."},
[20166]={"Seal of Wisdom","135 Mana\nInstant\n[q]Fills the Paladin with divine wisdom for 30 sec, giving each melee attack a chance to restore 50 of the Paladin's mana. Only one Seal can be active on the Paladin at any one time.\n\n Unleashing this Seal's energy will judge an enemy for 20 sec, granting attacks and spells used against the judged enemy a chance to restore 33 mana to the attacker. Your melee strikes will refresh the spell's duration. Only one Judgement per Paladin can be active at any one time."},
